cpp知识补充01 - 侯捷 - C++面向对象高级开发（上下两部曲） 02 - 侯捷 - STL标准库和泛型编程 03 - 侯捷 - C++设计模式 04 - 侯捷 - C++新标准C++11&amp;14 05 - 侯捷 - C++内存管理机制 06 - 侯捷 C++ Startup 揭密：C++ 程序的生前和死后 07、算法原理与实践（选修） 08、系统设计与实践（选修） 书籍:c++ primer effective modern c++ stl源码剖析 前言拿来当c++知识点补充库，顺序不是按照学习的顺序，是感觉哪个不会了，看书或视频补充知识点。 namespace定义命名空间//如果不引入 using namespace std;就需要我们显示引入,例如std::coutnamespace a&#123; int a = 10;&#125;namespace b&#123;int a = 20;namespace c&#123; int a = 30;&#125;&#125;使用命名空间void main()&#123; using namespace a; using namespace b; cout &lt;&lt; a::a &lt;&lt; endl; cout &lt;&lt; b::a &lt;&lt; endl; cout &lt;&lt; b::c::a &lt;&lt; endl; using b::c::a; cout &lt;&lt; a; system(&quot;pause&quot;);&#125; 不使用using namespace std 原因：如果没有命名空间，这些变量、函数、类的名称将都存在于全局命名空间中，当定义了一个函数名与标准库中函数名相同时，就会发生冲突。比如，我们在自己的程序中定义了一个Stack类，而我们程序中使用的某个库中也可能定义了一个同名的类，此时名称就冲突了。 顶层const和底层constconst修饰的变量不可以改变就是顶层const：const int a = 10;底层const：const int &amp;ra = 10; c++ primer :当执行对象的拷贝操作时，常量的顶层const不受什么影响，而底层const必须一致 const引用理解: 1.引用不是对象且不进行拷贝 2.常量引用如果在左侧，右侧可以接任何东西 3.非常量引用 = 常量 error 4.引用如果在等号右侧请忽略引用 5.非常量 = 常引用 判断方法: 代码详解:void main()&#123; int i = 0; const int p = 10;//顶层const(不能被修改) const int* p1 = &amp;p; p1 = &amp;i;//底层const 允许修改p1的值 const 修饰的是int 不能改变的是 *p1 int *p1是个指针，地址没变，里面值改变无所谓 const修饰的是什么,p1就指向的是什么 *p就相当于（const int）*p int* const p2 =&amp;i;//顶层const p2的值不允许被修改 p2是个指针，里面存放的是地址，地址是不可以改变的，值是可以改变的。 const int*p2 然后你可以通过改变p2指向这个内存地址里的值,来改变p2读出来的值 system(&quot;pause&quot;);&#125;const int* p1 = &p; p1是一个指向const int类型的指针变量。&amp;p是一个指向int类型变量p的地址。通过将&amp;p赋值给p1，p1成为了一个指向p的const int类型的指针。这意味着p1指向的int类型的数据是只读的，不能通过p1来修改。int* const p2 = &i; p2是一个指向int类型的常量指针变量。&amp;i是一个指向int类型变量i的地址。通过将&amp;i赋值给p2，p2成为了一个指向i的int类型的常量指针。这意味着p2指向的int类型数据可以修改，但是p2本身的指向是不可变的，即p2不能指向其他的地址。 register 加强register 关键字请求编译器将局部变量存储于寄存器中。void main()&#123; register int a = 0; std::cout&lt;&lt;&amp;a&lt;&lt;endl; system(&quot;pause&quot;);&#125; 引用剖析引用语法void main()&#123; int a = 10; int &amp;b = a;//b就是a的别名 int *const b = &amp;a b= 11;//*b = 11 &#125; 引用本质引用在c++内部实现是一个常量指针Type&amp; name&lt;——&gt;Type * const name 函数返回值是引用int *get_1()&#123; int a = 10; return &amp;a;&#125;//返回的是本身的一个副本(20)int&amp; get_2()&#123; int a = 20; return a;&#125;void main()&#123; int a2 = get_2();//20 int &amp;a3 = get_2();//返回的是a的本身 地址&#125; 若返回静态变量或全局变量可以成为其他引用初始值既可以作为右值使用，也可以作为左值使用 int g1()&#123; int a = 2; return a;&#125;int&amp; g2()&#123; static int a = 10; a++; return a;&#125;void main()&#123; g1() =100;//error g2() = 100;//返回的是变量本身 g2()返回的a当左值使用 system(&quot;pause&quot;);&#125; inline 内联函数 用来代替宏代码片段 inline void fun() &#123; int a = 10; cout&lt;&lt;a&lt;&lt;endl;&#125;void main()&#123; &#125; #define Myfunc(a,b)((a)&lt;(b)？(a):(b)) inline int myfunc(int a,int b) &#123; return a&lt;b?a:b&#125; int main() &#123; int c1 = myfunc(++a,b)//a=2 b = 3 c =2 int c2 = Myfunc(++a,b)//==&gt;宏展开((++a)&lt;(b)?(++a):(b)) return 0;&#125; 内联不能做声明，必须和函数体实现写在一块adsd 构造函数和析构函数基本概念 构造函数：完成对属性的初始化工作（先创建的对象先构造） 析构函数：先创建的对象后释放（栈机制） 构造函数分类class test&#123; private: int a,b,c,d; public: test()//无参构造 &#123; &#125; test(int a,int b)//有参构造 &#123; this-&gt;a = a; this-&gt;b = b; &#125; test(const test&amp; obj)//赋值构造函数 &#123; &#125;&#125;void main()&#123; test t2//无参构造 test t(2,4);//有参调用 test t1(t);//拷贝构造&#125; 深拷贝和浅拷贝问题浅拷贝分析默认的拷贝构造函数，编译器提供把对象1的属性拷贝给对象二把指针变量的值拷贝给对象二，并没有把指针变量所指向的内存空间的数据拷贝过来两个指针变量指向同一个空间 obj2析构函数 把指向的内存空间析构obj2 指向null，obj1仍然指向堆里被释放的内存空间。obj1再析构，还是析构的obj2之前析构的那一块空间，，结果析构两次，造成空间的coredump coredump出现原因: 等号操作也是浅拷贝操作临时对象生命周期构造之后马上析构 构造函数中调用构造函数危险行为 new 和delete基本语法int *arr = new int[10];delete []arr;//动态分配对象object *pt = new object;delete pt; 面向对象友元函数和友元类友元函数#include&lt;iostream&gt;using namespace std;class A&#123;public: friend void modify(A* pa,int _a); A(int a, int b) &#123; this-&gt;a = a; this-&gt;b = b; &#125; void geta() &#123; cout&lt;&lt;this-&gt;a; &#125; //声明位置和public和private没关系private: int a; int b;&#125;;void modify(A* pa,int _a)&#123; pa-&gt;a = _a;&#125;int main(void)&#123; A a(5, 3); modify(&amp;a, 100); a.geta(); return 0;&#125; 友元类重载运算符这两个都写在vs里了 继承概念访问父类的语法和概念派生类的访问控制类的单个类访问控制//public 修饰地成员变量方法在类的内部 类的外部都能使用//protected 修饰的成员变量方法，在类的内部使用，在继承的子类中可用//private 修饰地成员变量方法只能在类的内部使用 类的外部不行class Test&#123; public: int a; void printT() &#123; cout&lt;&lt;&quot;printT&quot;; &#125; protected: int b; private: int c;&#125;;class test:public Test&#123; public: void user() &#123; a = 0;//ok b= 0;//ok c = 0;//error 私有变量 &#125;&#125;; protect 关键字修饰变量使用，是为了继承 继承中构造和析构//赋值兼容性原则//1.基类指针(引用)指向子类对象 可以调用父类方法class Parent&#123; private: int a; int b; public: Parent(int a1,int b1):a(a1),b(b1)&#123;&#125; &#125;class child&#123;private:int c;public:child(int a,int b,int c1):parent(a,b),c(c1)&#123;&#125;&#125; 继承和虚函数virtual函数:你希望derived class 重新定义它，且你对他已有默认定义pure virtual 函数:erived class 重新定义它，且你对他没有默认定义 复合和继承委托和继承 抽象基类class person//抽象基类(类似于接口)&#123;protected: string name; int height; int age;public: virtual void getinfo() const = 0;//纯虚函数 virtual void action() = 0; string getname() &#123; return name; &#125; person(string&amp; s, int h,int a) :name(s), height(h),age(a) &#123;&#125;&#125;;class dancer :public person&#123;private: string danceaction;public: dancer(string na,int h, int a, string ac) :person(na,h,a) &#123; danceaction = ac; &#125; void getinfo() const &#123; cout &lt;&lt; &quot;name:&quot; &lt;&lt; name &lt;&lt; endl; cout &lt;&lt; &quot;height:&quot; &lt;&lt; height &lt;&lt; endl; cout &lt;&lt; &quot;age:&quot; &lt;&lt; age &lt;&lt; endl; cout &lt;&lt; &quot;danceaction:&quot; &lt;&lt;danceaction&lt;&lt; endl; &#125; void action() &#123; cout &lt;&lt; &quot;dance&quot; &lt;&lt; endl; &#125;&#125;; 设计抽象类（通常称为 ABC）的目的，是为了给其他类提供一个可以继承的适当的基类。抽象类不能被用于实例化对象，它只能作为接口使用。如果试图实例化一个抽象类的对象，会导致编译错误。因此，如果一个 ABC 的子类需要被实例化，则必须实现每个纯虚函数，这也意味着 C++ 支持使用 ABC 声明接口。如果没有在派生类中重写纯虚函数，就尝试实例化该类的对象，会导致编译错误。可用于实例化对象的类被称为具体类。https://www.runoob.com/cplusplus/cpp-interfaces.html 继承的动态内存分配基类使用动态内存分配，派生类不使用动态内存分配。可以省略构造函数和析构函数中的内存分配和释放操作，直接继承基类中的构造和析构函数。class Base &#123;public: Base(const char* str) &#123; data_ = new char[strlen(str) + 1]; strcpy(data_, str); &#125; virtual ~Base() &#123; delete[] data_; &#125; const char* getData() const &#123; return data_; &#125;private: char* data_;&#125;;// 派生类，不使用动态内存分配class Derived : public Base &#123;public: Derived(const char* str, int value) : Base(str), value_(value) &#123;&#125; int getValue() const &#123; return value_; &#125;private: int value_;&#125;; 基类使用动态内存分配，派生类也使用动态内存分配class BASE&#123;private: char* base;public: BASE(const char *str) &#123; base = new char[strlen(str) + 1]; strcpy(base, str); &#125; virtual ~BASE() &#123; delete[]base; &#125; BASE&amp; operator=(const BASE&amp; str) &#123; if (this == &amp;str) &#123; return *this; &#125; delete[]base; base = new char[strlen(str.base) + 1]; strcpy(base,str.base); return *this; &#125;&#125;;class derived :public BASE&#123;private: char* dervived;public: derived(const char* str):BASE(str) &#123; dervived = new char[strlen(str) + 1]; strcpy(dervived, str); &#125; derived&amp; operator=(const derived&amp; str) &#123; if (this == &amp;str) &#123; return *this; &#125; delete[]dervived; BASE::operator=(str); dervived = new char[strlen(str.dervived) + 1]; strcpy(dervived, str.dervived); return *this; &#125; ~derived() &#123; delete[] dervived; &#125;&#125;; conversion functionclass fraction&#123;private: int numrator; int denominator;public: fraction(int num, int den = 1) :numrator(num), denominator(den) &#123;&#125; operator double() const &#123; return double(numrator * 1.0 / denominator); &#125;&#125;;int main(void)&#123; fraction f(3, 5); double d = f + 4; cout &lt;&lt; d; return 0;&#125; double d = 4 + f;这一语句会首先查找Fraction是否有重载操作符 operator + (double, Fraction) 的函数，由于没有，所以调用会转换函数operator double() const。 另外，转换函数除了可以将一个类型转换成另一个基本类型，还可以将一个类型转换成另一个复合类型（例如string类型）。 non -explicit-one-argument ctorclass Fraction &#123;public: Fraction(int num, int den=1) : m_numerator(num), m_denominator(den) &#123;&#125; Fraction operator + (const Fraction&amp; f) &#123; return Fraction(...); &#125;private: int m_numerator; // 分子 int m_denominator; // 分母&#125;;Fraction f(3, 5);Fraction d2 = f + 4; 只要一个实参就够了，也可以传两个实参。将别的东西转换成这个类对象 conversion function vs. non-explicit-one-argument constructorexplicit-one-argument constructorclass Fraction &#123;public: explicit Fraction(int num, int den=1) : m_numerator(num), m_denominator(den) &#123;&#125; operator double() const &#123; return (double) (m_numerator / m_denominator); &#125; Fraction operator + (const Fraction&amp; f) &#123; return Fraction(...); &#125;private: int m_numerator; // 分子 int m_denominator; // 分母&#125;;Fraction f(3, 5);Fraction d2 = f + 4; // [Error] convertion from double to Fraction requested 由于在构造函数前面增加了explicit关键字，所以不能将4转换成Fraction类型；也不能先将f转换成double类型，与4相加后再将double转换成Fraction。 pointer like classes智能指针智能指针是你在堆栈上声明的类模板，并可通过使用指向某个堆分配的对象的原始指针进行初始化。 在初始化智能指针后，它将拥有原始的指针。 这意味着智能指针负责删除原始指针指定的内存。 智能指针析构函数包括要删除的调用，并且由于在堆栈上声明了智能指针，当智能指针超出范围时将调用其析构函数，尽管堆栈上的某处将进一步引发异常。 C++ 中有三种常用的智能指针： unique_ptr：独占所有权的智能指针，不能被复制，只能被移动。当 unique_ptr 超出作用域时，它所指向的对象会被自动释放。 shared_ptr：共享所有权的智能指针，可以被多个 shared_ptr 共享。当最后一个 shared_ptr 超出作用域时，它所指向的对象会被自动释放。 weak_ptr：弱引用的智能指针，不能直接访问所指向的对象，必须通过 lock() 函数获得一个 shared_ptr 才能访问。weak_ptr 不会增加所指对象的引用计数，因此不会影响所指对象的生命周期。 shared_ptr用法：#include&lt;memory&gt;shared_ptr&lt;double&gt; p1(new double(42));shared_ptr&lt;int&gt;p2= make_shared&lt;int&gt;(42);拷贝和赋值auto r = make_shared&lt;int&gt;(42);//r指向int只有一个引用r=q;//给r赋值 //q指向的对象引用次数++ //r指向对象引用次数-- //r没有引用了，就会自动释放离开作用域，它指向内存也会自动释放但是如果有其他智能指针也指向这块内存，他就不会被释放void use_factory(T arg)&#123; shared_ptr&lt;Foo&gt; p = factory(arg); return p;//引用计数增加&#125;//离开作用域但不会被释放 迭代器fuction like classes 模板类模板函数模板成员模板 模板特化template&lt;&gt;struct hash&lt;char&gt;&#123; size_t operator()(char x) const&#123; return x;&#125;&#125;;template&lt;&gt;struct hash&lt;int&gt;&#123; size_t operator()(int x) const&#123; return x;&#125;&#125;;template&lt;&gt;struct hash&lt;long&gt;&#123; size_t operator()(long x) const&#123; return x;&#125;&#125;; 偏特化(局部特化)template&lt;class T,class alloc&gt; class name&#123;&#125;;template&lt;class alloc&gt;class name&lt;bool, alloc&gt; &#123;&#125;; 范围的偏template&lt;class T&gt;class c&#123;&#125;;template&lt;class T&gt;class c&lt;T*&gt;&#123;&#125;;如果使用者使用的是指针就用第二个模板如果不是指针，用的是第一个模板 模板模板参数template&lt;class T,template&lt;class T&gt; class smartptr&gt;//第一个参数是 T类型 ，第二个参数是一个smartptr，它可以指定一个T类型变量class XCls&#123; private: smartptr&lt;T&gt; sp; public: XCls():sp(new T)&#123;&#125;&#125;;XCls&lt;string,shared_ptr&gt; p1; 三个主题packtemplate&lt;typename T,typename...Types&gt;void print(const T&amp;firstArg,const Type&amp;...args)&#123; cout&lt;&lt;firstArg&lt;&lt;endl; print(args...);&#125; 用sizeof…(args)可以知道包有多少 autoauto声明变量必须要赋值 ranged-base forvector&lt;double&gt; vec;for(auto elem:vec)&#123; cout&lt;&lt;elem&lt;&lt;endl;&#125;for(auto&amp; elem:vec)&#123; elem*=3;&#125;//改变原来vec里的值 referenceint x = 0;int* p = &amp;x;int&amp; r =x;//r代表x,r不能代表其他的了int x2 = 5;r = x2;//r不能代表x，现在r,x都是5int&amp; r2 =r; reference一定要有初值，只能代表一个，不能代表其他 32位电脑指针占四个字节 参数传递 this重载new(),delete()class Foo &#123;public: void* operator new(std::size_t size) &#123; std::cout &lt;&lt; &quot;operator new&quot; &lt;&lt; std::endl; return std::malloc(size); &#125; void operator delete(void* ptr)&#123; std::cout &lt;&lt; &quot;operator delete&quot; &lt;&lt; std::endl; std::free(ptr);&#125;&#125;int main()&#123; Foo* m = new Foo; std::cout &lt;&lt; sizeof(m) &lt;&lt; std::endl; delete m; return 0; &#125; 在类中的operator new默认就是static。所以加static可以，不加也是全局，可以正常使用。 这种重载的意义是和重载operator new配套。只有operator new报异常了，就会调用对应的operator delete。若没有对应的operator delete，则无法释放内存。 STL学习网址：zh.cppreference.com 容器array相比于普通数组，array容器访问速度快，安全性高，在传递方式方面，普通数组作为函数参数时，实际上是传递一个指向数组首元素的指针。而array容器作为函数参数时，实际上传递的是整个array容器的值。td::array&lt;int, 5&gt; myarr; std::array&lt;int, 5&gt; a2; for (int i =0;i&lt;myarr.size();i++) &#123; std::cin &gt;&gt; myarr[i]; &#125; for (auto it = myarr.begin(); it != myarr.end(); it++) &#123; std::cout &lt;&lt; *it &lt;&lt; &quot; &quot;; &#125; std::cout &lt;&lt; &quot;
&quot;; std::sort(myarr.begin(),myarr.end());//算法库 std::ostream_iterator&lt;int&gt; output(std::cout,&quot; &quot;); std::reverse_copy(myarr.begin(), myarr.end(), a2.begin()); std::reverse_copy(myarr.begin(), myarr.end(), output); std::array&lt;std::string, 5&gt; a3 = &#123; &quot;aefea&quot;,std::string(&quot;a&quot;) &#125;; for (auto&amp; s : a3) &#123; std::cout &lt;&lt; s &lt;&lt; &quot; &quot;; &#125;上述代码中，sort是algorithm库中函数，能将容器内元素从大到小排序，reversecopy函数详见cppconference vector能动态调整大小，存储相同类型元素std::vector&lt;int&gt; vec; std::vector&lt;int&gt; vec2(5); std::vector&lt;int&gt; vec3(5, 42); std::vector&lt;int&gt; vec4(vec3); vec.push_back(10); vec.push_back(20); //vec.pop_back();//删除末尾元素 int first = vec[0]; // 使用数组下标访问元素 int second = vec.at(1); // 使用at()方法访问元素，会检查下标是否越界 //获取容量 size_t size = vec.size();//获取向量大小 size_t capacity = vec.capacity();//分配内存空间大小 //迭代访问 for (auto i : vec) &#123; std::cout &lt;&lt; i&lt;&lt;std::endl; &#125; for (auto it = vec.begin(); it != vec.end(); it++) &#123; std::cout &lt;&lt; *it &lt;&lt; std::endl; &#125;data()返回值 : 指向底层元素存储的指针。对于非空容器，返回的指针与首元素地址比较相等。例子：void span_func(std::span&lt;const int&gt; data) // C++20 起&#123; std::cout &lt;&lt; &quot;data = &quot;; for (const int e : data) std::cout &lt;&lt; e &lt;&lt; &#x27; &#x27;; std::cout &lt;&lt; &#x27;
&#x27;;&#125;int main()&#123;std::span&lt;int&gt; s&#123;container.data(),container.size() &#125;;span_func(s);&#125;注：span 是c++20新特性 list双向链表std::list&lt;int&gt; l = &#123;7,5,16,8&#125;; l.push_back(25);//添加末尾 l.push_front(15);// 开头 std::list&lt;int&gt;::iterator it = std::find(l.begin(),l.end(),16);//用迭代器找到16的位置 if(it!=l.end()) l.insert(it, 42); std::cout &lt;&lt; *it&lt;&lt;&quot;
&quot;; //迭代打印 for (auto i : l) &#123; std::cout &lt;&lt; i &lt;&lt; &quot; &quot;; &#125;还有pop_back等用法在笔记中不一 一实例了，cppconference中有实例。 list 的原理： list 是通过双向链表实现的，每个节点都包含了指向前一个节点和后一个节点的指针。因此，插入和删除元素时只需要修改相关节点的指针即可，不需要像数组那样进行元素的移动。 由于 list 中的元素是通过指针进行连接的，因此在访问 list 中的元素时，需要通过迭代器来进行访问。迭代器是指向 list 中元素的指针，支持 ++ 操作来遍历 list 中的元素 forward list单向列表（单链表）只能从一端进入和移除，所以只能从容器起始插入和删除 queue(容器的适配器 )队列queue是一个单口进出的数据结构，没有迭代器first in first out deque双端队列可以两边扩充 在 C++ STL 中，deque（双端队列）是一种常用的容器，它可以在两端进行插入和删除操作，并且支持随机访问。deque 内部使用一个动态数组来存储元素，可以动态调整大小以适应元素的添加和删除，同时还可以在数组的两端进行快速插入和删除操作，因此可以高效地实现队列和栈等数据结构。 简单用法例子：std::deque&lt;int&gt; de(10); /*de.push_back(5); de.push_front(10);*/ std::deque&lt;int&gt;::iterator it = de.begin(); for (it; it != de.end(); it++) &#123; int x = 0; std::cin &gt;&gt; x; *it = x; &#125; for (auto i : de) &#123; std::cout &lt;&lt; i; &#125; stack(容器的适配器)栈和队列都是不能直接通过构造函数分配元素数量的，必须通过封装vector来实现具体例子：std::vector&lt;int&gt; v(10, 0); std::stack&lt;int&gt; s(v); set 红黑树set 中存储的元素是唯一的，插入重复元素会被忽略 multiset(红黑树)含有 Key 类型对象有序集的容器。与 set 不同，它允许多个 Key 拥有等价的值。用关键比较函数 Compare 进行排序。搜索、插入和移除操作拥有对数复杂度。 unordered_multiset(哈希表)篮子不能太长，如果元素的个数大于等于篮子，篮子就要重新扩充大于等于两倍的元素个数 unordered_set (哈希表）四个容器区别总结set 和 multiset 是基于红黑树实现的关联容器，可以快速插入、删除、查找元素，并且元素默认按照元素值从小到大排序，但插入、删除和查找等操作的时间复杂度为 O(log n)。 unordered_set 和 unordered_multiset 是基于哈希表实现的关联容器，可以快速插入、删除、查找元素，并且插入、删除和查找等操作的时间复杂度为 O(1)，但元素没有固定的顺序。 在选择使用哪种容器时，需要考虑元素是否需要排序以及对性能的要求。如果元素需要排序，且对性能要求不是非常高，可以选择 set 或 multiset；如果对性能要求比较高，可以选择 unordered_set 或 unordered_multiset。 四个容器的用法：//1.定义std::set&lt;int&gt; s;std::multiset&lt;int&gt; ms;std::unordered_multiset&lt;int&gt; ums;std::unordered_set&lt;int&gt; us;//2.插入s.insert(5);s.insert(2);ms.insert(3);ms.insert(4);/*后面两个容器也一样*///3.查找元素auto it = s.find(2);//返回的是迭代器指针std::cout &lt;&lt; *it;//4.遍历for (auto it = s.begin(); it != s.end(); ++it) &#123; std::cout &lt;&lt; *it &lt;&lt; &quot; &quot;; // 输出 set 容器中的元素&#125;for (auto it = ms.begin(); it != ms.end(); ++it) &#123; std::cout &lt;&lt; *it &lt;&lt; &quot; &quot;; // 输出 multiset 容器中的元素&#125;for (auto i : ms)&#123; std::cout &lt;&lt; i&lt;&lt;&quot; &quot;;&#125;for (auto i : s)&#123; std::cout &lt;&lt; i&lt;&lt;&quot; &quot;;&#125;//5.合并s.merge(ms); mapMap是C++ STL中的一个关联式容器，它提供了一种映射关系的数据结构，即一组key-value对，其中key是唯一的，value可以重复。Map中的元素是按照key的大小进行排序的，因此可以进行快速的查找和插入操作。Map支持[]和insert等操作，可以通过迭代器进行遍历。Map的底层实现一般采用红黑树，因此它的插入、删除和查找操作的时间复杂度都是O(log n)。 用法：/*插入，创建，初始化,修改*/ std::map&lt;std::string, int&gt; m&#123; &#123;&quot;CPU&quot;,10&#125; ,&#123;&quot;GPU&quot;,20&#125;&#125;; m.insert(std::pair&lt;std::string, int&gt;(&quot;ARM&quot;, 35));//插入 m[&quot;ARM&quot;] = 45; m[&quot;Map&quot;] = 15;//插入新值 /*遍历方法*/ for (const auto&amp; [key, value] : m) std::cout &lt;&lt; &#x27;[&#x27; &lt;&lt; key &lt;&lt; &quot;] = &quot; &lt;&lt; value &lt;&lt; &quot;; &quot;; for (auto it = m.begin(); it != m.end(); it++) &#123; std::cout &lt;&lt; it-&gt;first &lt;&lt; &quot; &quot; &lt;&lt; it-&gt;second; &#125; multimapMultimap是一个允许重复键的Map，它也是一个关联式容器，提供了一种映射关系的数据结构，其中一组key-value对中的key可以重复，而value可以不重复。Multimap的元素同样是按照key的大小进行排序的，并且支持[]和insert等操作，可以通过迭代器进行遍历。Multimap的底层实现一般采用红黑树，因此它的插入、删除和查找操作的时间复杂度也都是O(log n)。 用法：//2.multimap std::multimap&lt;std::string, int&gt; m; m.insert(std::pair&lt;std::string, int&gt;(&quot;map&quot;, 10)); m.insert(std::pair&lt;std::string, int&gt;(&quot;map&quot;, 10)); m.insert(std::pair&lt;std::string, int&gt;(&quot;map&quot;, 10)); //m[&quot;map&quot;] = 15;//没有[]操作符 error for (auto it = m.begin(); it != m.end(); it++) &#123; std::cout &lt;&lt; it-&gt;first &lt;&lt; &quot; : &quot; &lt;&lt; it-&gt;second &lt;&lt;std:: endl; &#125;Multimap的用法和Map类似，只是插入操作不会覆盖已有的键值对。 unordered_multimapunordered_multimap是一个允许重复键的unordered_map，它也是一个哈希表，提供了一种映射关系的数据结构，其中一组key-value对中的key可以重复，而value可以不重复。unordered_multimap中的元素是按照哈希值进行存储的，因此查找和插入操作的时间复杂度是O(1)。 用法：unordered_map的用法和Map类似，只是底层实现不同，插入操作的时间复杂度为O(1)。 unordered_mapunordered_map是C++ STL中的一个哈希表，它提供了一种映射关系的数据结构，其中一组key-value对中的key是唯一的，而value可以重复。unordered_map中的元素是按照哈希值进行存储的，因此查找和插入操作的时间复杂度是O(1)。 用法：unordered_multimap的用法和unordered_map类似，只是允许键值对中的键重复。 区别总结Map和Multimap都是基于红黑树实现的，而unordered_map和unordered_multimap都是基于哈希表实现的。因此，Map和Multimap的插入、删除和查找操作的时间复杂度都是O(log n)，而unordered_map和unordered_multimap的插入、删除和查找操作的时间复杂度都是O(1)。另外，Map和Multimap中的元素是按照key的大小进行排序的，而unordered_map和unordered_multimap中的元素是按照哈希值进行存储的，因此它们的遍历顺序可能不同。此外，Multimap和unordered_multimap允许重复键，而Map和unordered_map不允许重复键。 补充stl算法upper_boundstd::vector&lt;int&gt; v = &#123;1, 2, 3, 4, 4, 6, 7, 8, 9&#125;; auto it = std::upper_bound(v.begin(), v.end(), 4); if (it != v.end()) &#123; std::cout &lt;&lt; &quot;The first element greater than 4 is: &quot; &lt;&lt; *it &lt;&lt; std::endl; &#125; else &#123; std::cout &lt;&lt; &quot;No element greater than 4&quot; &lt;&lt; std::endl; &#125; std::upper_bound将返回一个迭代器，指向第一个大于value的元素。如果不存在这样的元素，std::upper_bound将返回last。
